mapper.select:
select n.*,
       coalesce(u.user_no, '') as sender_user_no,
       coalesce(u.nickname, '') as sender_nickname,
       coalesce(u.avatar_url, '') as sender_avatar_url
from app_notification n
         left join app_user u on u.id = n.sender_user_id
where n.user_id = #{userId}
  and n.create_time >= #{sinceTime}
order by n.create_time desc, n.id desc
limit #{limit}

select count(*)
from app_notification
where user_id = #{userId}
  and read_flag = 0
  and create_time >= #{sinceTime}

